class Solution:
    def findMinHeightTrees(self, n, edges):
        from collections import deque
        adj = [[] for _ in range(n)]
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        def height(src):
            seen = [False] * n
            seen[src] = True
            q = deque([src])
            h = -1
            while q:
                h += 1
                for _ in range(len(q)):
                    u = q.popleft()
                    for w in adj[u]:
                        if not seen[w]:
                            seen[w] = True
                            q.append(w)
            return h
        hs = [height(i) for i in range(n)]
        best = min(hs)
        return [i for i in range(n) if hs[i] == best]

