class Solution:
    def findMinHeightTrees(self, n, edges):
        if n == 1:
            return [0]
        adj = [set() for _ in range(n)]
        for a, b in edges:
            adj[a].add(b)
            adj[b].add(a)
        leaves = [i for i in range(n) if len(adj[i]) == 1]
        remaining = n
        while remaining > 2:
            remaining -= len(leaves)
            nxt = []
            for leaf in leaves:
                nb = adj[leaf].pop()
                adj[nb].discard(leaf)
                if len(adj[nb]) == 1:
                    nxt.append(nb)
            leaves = nxt
        return leaves

